import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { Keypair } from '@solana/web3.js';
import bs58 from 'bs58';

export default function WalletsPage() {
  const { 
    wallets, 
    balances,           // ADDED: Get balances from context
    addWallet, 
    importWallet, 
    removeWallet, 
    addLog,
    refreshWalletBalances,  // ADDED: Get refresh function
    connection          // ADDED: Check connection
  } = useApp();

  const [importKey, setImportKey] = useState('');
  const [showSecret, setShowSecret] = useState({});
  const [storageStatus, setStorageStatus] = useState('checking');

  // Check storage on mount
  useEffect(() => {
    const checkStorage = () => {
      try {
        const test = localStorage.getItem('nexus-app-wallets');
        setStorageStatus('available');
      } catch (e) {
        setStorageStatus('unavailable');
      }
    };
    checkStorage();

    // Auto-refresh balances when page loads
    if (wallets.length > 0) {
      refreshWalletBalances();
    }
  }, [wallets.length, refreshWalletBalances]);

  const createWallet = async () => {
    try {
      const wallet = await addWallet();
      if (wallet) {
        addLog(`Created wallet: ${wallet.publicKey.slice(0, 20)}...`, 'success');
      }
    } catch (err) {
      addLog(`Error creating wallet: ${err.message}`, 'error');
    }
  };

  const handleImportWallet = async () => {
    try {
      let secretKey;

      // Try Base58
      try {
        secretKey = bs58.decode(importKey);
      } catch {
        // Try JSON array
        secretKey = new Uint8Array(JSON.parse(importKey));
      }

      const wallet = await importWallet(null, secretKey);
      if (wallet) {
        setImportKey('');
        addLog(`Imported wallet: ${wallet.publicKey.slice(0, 20)}...`, 'success');
      }
    } catch (err) {
      addLog(`Import failed: ${err.message}`, 'error');
      alert('Invalid private key format');
    }
  };

  const exportWallet = (index) => {
    const wallet = wallets[index];
    const secret = Array.from(wallet.keypair.secretKey);
    const base58 = bs58.encode(wallet.keypair.secretKey);

    alert(`Wallet: ${wallet.publicKey}\n\nPrivate Key (Base58):\n${base58}\n\nJSON Array:\n${JSON.stringify(secret)}`);
  };

  const toggleSecret = (index) => {
    setShowSecret({ ...showSecret, [index]: !showSecret[index] });
  };

  const handleRemoveWallet = (publicKey) => {
    if (window.confirm('Are you sure you want to remove this wallet?')) {
      removeWallet(publicKey);
    }
  };

  // Format balance display
  const formatBalance = (publicKey) => {
    const bal = balances[publicKey];
    if (bal === undefined) return 'Loading...';
    if (bal === 0) return '0 SOL';
    return `${bal.toFixed(4)} SOL`;
  };

  return (
    <div>
      {/* Storage Status Warning */}
      {storageStatus === 'unavailable' && (
        <div style={{ 
          background: 'rgba(255, 0, 0, 0.2)', 
          border: '1px solid #ff4444',
          color: '#ff4444',
          padding: '10px',
          marginBottom: '16px',
          borderRadius: '8px',
          fontSize: '12px'
        }}>
          ⚠️ Storage unavailable! Wallets won't persist after reload.
        </div>
      )}

      {/* Connection Status */}
      <div style={{ 
        background: connection ? 'rgba(0, 255, 0, 0.1)' : 'rgba(255, 170, 0, 0.1)',
        border: `1px solid ${connection ? '#00ff00' : '#ffaa00'}`,
        color: connection ? '#00ff00' : '#ffaa00',
        padding: '8px',
        marginBottom: '16px',
        borderRadius: '8px',
        fontSize: '11px',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center'
      }}>
        <span>{connection ? '🟢 Connected' : '🟡 No Connection'}</span>
        <button 
          onClick={refreshWalletBalances}
          style={{
            padding: '4px 8px',
            fontSize: '10px',
            background: 'rgba(0, 243, 255, 0.2)',
            border: '1px solid #00f3ff',
            color: '#00f3ff',
            cursor: 'pointer',
            borderRadius: '4px'
          }}
        >
          Refresh Balances
        </button>
      </div>

      <div className="glass-panel">
        <div className="section-label">// CREATE NEW WALLET</div>
        <button className="btn-primary" onClick={createWallet}>
          Generate New Wallet
        </button>
      </div>

      <div className="glass-panel">
        <div className="section-label">// IMPORT WALLET</div>
        <label>Private Key (Base58 or JSON)</label>
        <textarea
          value={importKey}
          onChange={e => setImportKey(e.target.value)}
          placeholder="Enter private key..."
          style={{ minHeight: '80px', marginBottom: '16px', width: '100%' }}
        />
        <button className="btn-secondary" onClick={handleImportWallet}>
          Import Wallet
        </button>
      </div>

      <div className="glass-panel">
        <div className="section-label">// MANAGED WALLETS ({wallets.length})</div>

        {wallets.length === 0 ? (
          <p style={{ color: '#0099cc', fontSize: '12px' }}>No wallets yet. Create or import one above.</p>
        ) : (
          wallets.map((wallet, index) => (
            <div key={wallet.publicKey} className="wallet-card" style={{ marginBottom: '16px', padding: '16px', background: 'rgba(0,0,0,0.3)', borderRadius: '8px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' }}>
                <strong>{wallet.name}</strong>
                <div>
                  <button 
                    className="btn-secondary" 
                    style={{ padding: '6px 12px', fontSize: '10px', marginRight: '8px' }}
                    onClick={() => toggleSecret(index)}
                  >
                    {showSecret[index] ? 'Hide' : 'Show'} Key
                  </button>
                  <button 
                    className="btn-secondary" 
                    style={{ padding: '6px 12px', fontSize: '10px', marginRight: '8px' }}
                    onClick={() => exportWallet(index)}
                  >
                    Export
                  </button>
                  <button 
                    className="btn-secondary" 
                    style={{ padding: '6px 12px', fontSize: '10px', background: 'rgba(255, 0, 0, 0.2)', color: '#ff4444' }}
                    onClick={() => handleRemoveWallet(wallet.publicKey)}
                  >
                    Remove
                  </button>
                </div>
              </div>

              {/* Wallet Address */}
              <div className="wallet-address" style={{ 
                fontFamily: 'monospace', 
                fontSize: '11px', 
                color: '#00f3ff',
                marginBottom: '8px',
                wordBreak: 'break-all'
              }}>
                {wallet.publicKey}
              </div>

              {/* BALANCE DISPLAY - THIS WAS MISSING! */}
              <div style={{ 
                background: 'rgba(0, 243, 255, 0.1)',
                border: '1px solid rgba(0, 243, 255, 0.3)',
                padding: '8px 12px',
                borderRadius: '6px',
                marginBottom: '8px',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center'
              }}>
                <span style={{ fontSize: '11px', color: '#666' }}>Balance:</span>
                <span style={{ 
                  fontSize: '14px', 
                  fontWeight: 'bold',
                  color: balances[wallet.publicKey] > 0 ? '#00ff00' : '#00f3ff'
                }}>
                  {formatBalance(wallet.publicKey)}
                </span>
              </div>

              {showSecret[index] && (
                <div style={{ 
                  marginTop: '12px', 
                  padding: '12px', 
                  background: 'rgba(255, 170, 0, 0.1)', 
                  border: '1px solid rgba(255, 170, 0, 0.3)',
                  borderRadius: '8px',
                  fontSize: '11px',
                  wordBreak: 'break-all',
                  color: '#ffaa00'
                }}>
                  <strong>SECRET KEY (NEVER SHARE):</strong><br/>
                  {bs58.encode(wallet.keypair.secretKey)}
                </div>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
}
